const Text = ({ className }: { className?: string }) => (
  <span className={cn('text-xl text-title', className)}>{env.brand.name}</span>
)

export const Logo = ({
  variant = 'default',
  classNames,
  className,
  style,
}: {
  variant?: 'default' | 'icon'
  className?: string
  classNames?: {
    icon?: {
      container?: string
      path?: string
    }
    text?: string
  }
  style?: React.CSSProperties
}) => {
  return (
    <div
      style={style}
      className={cn('relative flex items-center gap-3 w-fit', className)}
    >
      {variant === 'icon' ? (
        <Icon classNames={classNames} />
      ) : (
        <>
          <Icon classNames={classNames} />
          <Text className={classNames?.text} />
        </>
      )}
    </div>
  )
}

